import { useState, useEffect } from 'react';

function useMediaQuery(query) {
  const [matches, setMatches] = useState(() => window.matchMedia(query).matches);

  useEffect(() => {
    const mql = window.matchMedia(query);
    const handler = (e) => setMatches(e.matches);
    mql.addEventListener('change', handler);
    setMatches(mql.matches);
    return () => mql.removeEventListener('change', handler);
  }, [query]);

  return matches;
}

export default useMediaQuery;

import { useState, useEffect, useRef } from 'react';

function useThrottle(value, interval = 500) {
  const [throttled, setThrottled] = useState(value);
  const lastUpdated = useRef(Date.now());

  useEffect(() => {
    const now = Date.now();
    const elapsed = now - lastUpdated.current;

    if (elapsed >= interval) {
      setThrottled(value);
      lastUpdated.current = now;
    } else {
      const timer = setTimeout(() => {
        setThrottled(value);
        lastUpdated.current = Date.now();
      }, interval - elapsed);
      return () => clearTimeout(timer);
    }
  }, [value, interval]);

  return throttled;
}

export default useThrottle;

import { useReducer, useCallback } from 'react';

function useUndoRedo(initialState) {
  const [state, dispatch] = useReducer((s, action) => {
    switch (action.type) {
      case 'SET':
        return {
          past: [...s.past, s.present],
          present: action.value,
          future: []
        };
      case 'UNDO':
        if (s.past.length === 0) return s;
        return {
          past: s.past.slice(0, -1),
          present: s.past[s.past.length - 1],
          future: [s.present, ...s.future]
        };
      case 'REDO':
        if (s.future.length === 0) return s;
        return {
          past: [...s.past, s.present],
          present: s.future[0],
          future: s.future.slice(1)
        };
      default: return s;
    }
  }, { past: [], present: initialState, future: [] });

  const set = useCallback(val => dispatch({ type: 'SET', value: val }), []);
  const undo = useCallback(() => dispatch({ type: 'UNDO' }), []);
  const redo = useCallback(() => dispatch({ type: 'REDO' }), []);

  return { state: state.present, set, undo, redo, canUndo: state.past.length > 0, canRedo: state.future.length > 0 };
}

import { useState, useEffect, useRef, useCallback } from 'react';

function useDebounce(value, delay = 300) {
  const [debounced, setDebounced] = useState(value);
  const timerRef = useRef(null);

  useEffect(() => {
    timerRef.current = setTimeout(() => setDebounced(value), delay);
    return () => clearTimeout(timerRef.current);
  }, [value, delay]);

  const cancel = useCallback(() => clearTimeout(timerRef.current), []);
  const flush = useCallback(() => {
    clearTimeout(timerRef.current);
    setDebounced(value);
  }, [value]);

  return { debounced, cancel, flush };
}

import { useState, useEffect } from 'react';

function usePreferredLanguage() {
  const [language, setLanguage] = useState(navigator.language);

  useEffect(() => {
    const handler = () => setLanguage(navigator.language);
    window.addEventListener('languagechange', handler);
    return () => window.removeEventListener('languagechange', handler);
  }, []);

  return language;
}

export default usePreferredLanguage;

import { useState, useEffect, useRef, useCallback } from 'react';

function useIdle(timeout = 30000) {
  const [isIdle, setIsIdle] = useState(false);
  const timerRef = useRef(null);

  const reset = useCallback(() => {
    setIsIdle(false);
    clearTimeout(timerRef.current);
    timerRef.current = setTimeout(() => setIsIdle(true), timeout);
  }, [timeout]);

  useEffect(() => {
    const events = ['mousemove', 'keydown', 'scroll', 'touchstart', 'click'];
    events.forEach(e => window.addEventListener(e, reset));
    timerRef.current = setTimeout(() => setIsIdle(true), timeout);

    return () => {
      events.forEach(e => window.removeEventListener(e, reset));
      clearTimeout(timerRef.current);
    };
  }, [reset, timeout]);

  return isIdle;
}
